<template><section class="container"><h2>评论管理</h2><div class="page-actions"><select v-model="status" @change="page=1;load()"><option value="">all</option><option value="visible">visible</option><option value="hidden">hidden</option><option value="deleted">deleted</option><option value="pending">pending</option></select></div><div v-if="loading" class="loading"/><div v-else-if="error" class="error">{{error}}</div><table v-else class="admin-table"><tr><th>ID</th><th>内容</th><th>状态</th><th>操作</th></tr><tr v-for="c in items" :key="c.id"><td>{{c.id}}</td><td>{{c.content}}</td><td>{{c.status}}</td><td><select v-model="c._next"><option>visible</option><option>hidden</option><option>deleted</option><option>pending</option></select><button @click="update(c)">提交</button></td></tr></table><div class="pagination"><button :disabled="page<=1" @click="page--,load()">上一页</button><span>{{page}}</span><button :disabled="!hasNext" @click="page++,load()">下一页</button></div></section></template>
<script setup>import { ref,onMounted } from 'vue'; import { getAdminComments, updateCommentStatus } from '../../api/admin'; const loading=ref(false); const error=ref(''); const status=ref(''); const page=ref(1); const size=ref(10); const items=ref([]); const hasNext=ref(false)
const load=async()=>{loading.value=true; try{const d=await getAdminComments({status:status.value,page:page.value,size:size.value}); items.value=(d.records||d.list||[]).map(i=>({...i,_next:i.status})); hasNext.value=d.totalPages ? page.value<d.totalPages : items.value.length>=size.value}catch(e){error.value=e.message}finally{loading.value=false}}
const update=async(c)=>{await updateCommentStatus(c.id,{status:c._next,adminNote:''}); await load()}
onMounted(load)
</script>
